import ExcelJS from "exceljs";
import { saveAs } from "file-saver";

// 🔥 YOUR LOGO (base64)
const LOGO_BASE64 =
  "data:image/png;base64,"; // <-- keep your full string here

export const exportStyledExcel = async (data) => {
  const workbook = new ExcelJS.Workbook();
  const worksheet = workbook.addWorksheet("Transactions");

  // ✅ Add Logo (FIXED - no filename)
  const imageId = workbook.addImage({
    base64: LOGO_BASE64,
    extension: "png",
  });

  worksheet.addImage(imageId, {
    tl: { col: 0, row: 0 },
    ext: { width: 160, height: 80 },
  });

  // ✅ Company Name
  worksheet.mergeCells("C1:H2");
  const title = worksheet.getCell("C1");
  title.value = "Asian Roadways Transport Company";
  title.font = { size: 18, bold: true, color: { argb: "FFEA580C" } };
  title.alignment = { horizontal: "center", vertical: "middle" };

  // ✅ Subtitle
  worksheet.mergeCells("C3:H3");
  const subtitle = worksheet.getCell("C3");
  subtitle.value = "Transport Transactions Report";
  subtitle.font = { size: 14, bold: true, color: { argb: "FF1E3A8A" } };
  subtitle.alignment = { horizontal: "center" };

  // Spacer
  worksheet.addRow([]);
  worksheet.addRow([]);

  // ✅ Header Row
  const headerRow = worksheet.addRow([
    "S.No",
    "Date",
    "Type",
    "Amount",
    "Category",
    "Branch",
    "Remark",
  ]);

  headerRow.eachCell((cell) => {
    cell.font = { bold: true, color: { argb: "FFFFFFFF" } };
    cell.fill = {
      type: "pattern",
      pattern: "solid",
      fgColor: { argb: "FF1E3A8A" }, // blue
    };
    cell.alignment = { horizontal: "center" };

    // 🔶 Orange Border
    cell.border = {
      top: { style: "thin", color: { argb: "FFEA580C" } },
      left: { style: "thin", color: { argb: "FFEA580C" } },
      bottom: { style: "thin", color: { argb: "FFEA580C" } },
      right: { style: "thin", color: { argb: "FFEA580C" } },
    };
  });

  // ✅ Data Rows
  data.forEach((t, index) => {
    const row = worksheet.addRow([
      index + 1,
      t.date,
      t.type,
      t.amount,
      t.category,
      t.branch,
      t.remark || "",
    ]);

    row.eachCell((cell, colNumber) => {
      // Border
      cell.border = {
        top: { style: "thin", color: { argb: "FFEA580C" } },
        left: { style: "thin", color: { argb: "FFEA580C" } },
        bottom: { style: "thin", color: { argb: "FFEA580C" } },
        right: { style: "thin", color: { argb: "FFEA580C" } },
      };

      // Type styling
      if (colNumber === 3) {
        if (t.type === "income") {
          cell.fill = {
            type: "pattern",
            pattern: "solid",
            fgColor: { argb: "FF16A34A" }, // green
          };
        } else {
          cell.fill = {
            type: "pattern",
            pattern: "solid",
            fgColor: { argb: "FFEA580C" }, // orange
          };
        }
        cell.font = { color: { argb: "FFFFFFFF" }, bold: true };
        cell.alignment = { horizontal: "center" };
      }

      // Amount format
      if (colNumber === 4) {
        cell.numFmt = '"₹"#,##0';
      }
    });
  });

  // ✅ Column widths
  worksheet.columns = [
    { width: 8 },
    { width: 15 },
    { width: 12 },
    { width: 15 },
    { width: 20 },
    { width: 18 },
    { width: 25 },
  ];

  // ✅ Generate file
  const buffer = await workbook.xlsx.writeBuffer();

  saveAs(
    new Blob([buffer]),
    `ARTC_Transactions_${Date.now()}.xlsx`
  );
};